import psycopg2

def search_users(username=None, email=None, role=None, status=None):
    conn = psycopg2.connect("dbname='mydatabase' user='myuser' host='localhost' password='mypassword'")
    cur = conn.cursor()
    
    # Build the query based on the provided filter criteria
    query = "SELECT * FROM users"
    if username is not None:
        query += " WHERE username LIKE %s"
    if email is not None:
        query += " AND email LIKE %s"
    if role is not None:
        query += " AND role = %s"
    if status is not None:
        query += " AND status = %s"
    
    # Execute the query and retrieve the results
    cur.execute(query, (username, email, role, status))
    results = cur.fetchall()
    
    # Close the cursor and connection
    cur.close()
    conn.close()
    
    return results